INSERT INTO `course` (`id`, `title`, `short_description`, `description`, `outcomes`, `faqs`, `language`, `category_id`, `sub_category_id`, `section`, `requirements`, `price`, `discount_flag`, `discounted_price`, `level`, `user_id`, `thumbnail`, `video_url`, `date_added`, `last_modified`, `course_type`, `is_top_course`, `is_live_class`, `is_admin`, `status`, `course_overview_provider`, `meta_keywords`, `meta_description`, `is_free_course`, `multi_instructor`, `enable_drip_content`, `creator`, `expiry_period`, `upcoming_image_thumbnail`, `publish_date`) VALUES
(4, 'Workplace Violence Prevention Training- English', 'Cal-Osha Mandated Training', '<p><span style=\"font-family: Nunito;\">﻿</span><strong style=\"box-sizing: inherit; font-weight: bold; color: rgb(121, 120, 120); font-family: \"Titillium Web\", sans-serif; font-size: 12px; text-align: center;\"><span style=\"font-family: Verdana; background-color: rgb(255, 255, 255);\">Welcome to our Workplace Violence Prevention Training by HRC Service</span></strong></p><p><strong style=\"box-sizing: inherit; font-weight: bold; color: rgb(121, 120, 120); font-family: \"Titillium Web\", sans-serif; font-size: 12px; text-align: center;\"><span style=\"font-size: 16px; font-weight: 400;\">As part of our ongoing commitment to creating a safe and supportive workplace, we are implementing a Workplace Violence Prevention Program. The safety and well-being of our employees are of the utmost importance, and this program is designed to ensure that everyone understands how to recognize, prevent, and respond to potential threats of violence in the workplace</span><span style=\"font-family: Verdana; background-color: rgb(255, 255, 255);\"><br></span></strong><br></p>', '[\"Certification\",\"Compliance\"]', '{\"Why do I need this Training?\":\"It is mandated by the State of California and Cal-Osha\",\"How long is the training?\":\"Total including the video and quiz is about 10 minutes\"}', 'english', 4, 5, '[5]', '[\"Must be an employee of our client\"]', 0, NULL, 0, 'beginner', '1', NULL, 'https://youtu.be/sukk2G-e8ZY?si=cM4hBLl6yzbccmlY', 1726470000, 1771661599, 'general', 1, 0, 1, 'active', 'youtube', '', 'Protect your workplace with our comprehensive Workplace Violence Prevention Training. Learn how to identify, prevent, and manage potential threats. Tailored for HR professionals, managers, and employees, our expert-led course ensures compliance and promotes a safer work environment', 1, 0, 1, 1, NULL, NULL, ''),
(5, 'Workplace Violence Prevention Training- Spanish', 'Cal-Osha Mandated Training', '<p><span style=\"font-family: Nunito;\">﻿</span><strong style=\"box-sizing: inherit; font-weight: bold; color: rgb(121, 120, 120); font-family: \"Titillium Web\", sans-serif; font-size: 12px; text-align: center;\"><span style=\"font-family: Verdana; background-color: rgb(255, 255, 255);\">Welcome to our Workplace Violence Prevention Training by HRC Service</span></strong></p><p><strong style=\"box-sizing: inherit; font-weight: bold; color: rgb(121, 120, 120); font-family: \"Titillium Web\", sans-serif; font-size: 12px; text-align: center;\"><span style=\"font-size: 16px; font-weight: 400;\">As part of our ongoing commitment to creating a safe and supportive workplace, we are implementing a Workplace Violence Prevention Program. The safety and well-being of our employees are of the utmost importance, and this program is designed to ensure that everyone understands how to recognize, prevent, and respond to potential threats of violence in the workplace</span><span style=\"font-family: Verdana; background-color: rgb(255, 255, 255);\"><br></span></strong><br></p>', '[\"Certification\",\"Compliance\"]', '{\"Why do I need this Training?\":\"It is mandated by the State of California and Cal-Osha\",\"How long is the training?\":\"Total including the video and quiz is about 10 minutes\"}', 'english', 4, 6, '[5,11]', '[\"Must be an employee of our client\"]', 0, NULL, 0, 'beginner', '1', NULL, 'https://youtu.be/DNkQx1rLUYk', 1726470000, 1771661684, 'general', 1, 0, 1, 'active', 'youtube', '', 'Protect your workplace with our comprehensive Workplace Violence Prevention Training. Learn how to identify, prevent, and manage potential threats. Tailored for HR professionals, managers, and employees, our expert-led course ensures compliance and promotes a safer work environment', 1, 0, 1, 1, NULL, NULL, ''),
(7, 'Blood Borne Pathogens (BBP)', 'How to prevent Blood Borne Pathogens at workplace.', '<p>Welcome to HRC Service\'s training on Bloodborne Pathogens. This course is critical for anyone who may be exposed to blood on the job.</p>', '[]', '[]', 'english', 9, 12, '[23]', '[]', 0, NULL, 0, 'beginner', '1', NULL, 'https://youtu.be/49JuC99iR68?si=FjZjPVXz3BckLSlT', 1768204800, 1769085133, 'general', 1, 0, 1, 'active', 'youtube', '', '', 1, 0, 1, 1, NULL, NULL, ''),
(8, 'Bloodborne Pathogens (BBP) & Infection Control', 'Essential training on Bloodborne Pathogens (BBP) and Infection Control in accordance with OSHA 29 CFR 1910.1030. Learn how exposure occurs, how to stay protected, and how to respond safely in the workplace.', '<p style=\"text-align: justify;\">This course provides essential training on Bloodborne Pathogens (BBP) and Infection Control in compliance with OSHA 29 CFR 1910.1030. Delivered by HRC Service, the program educates participants on how bloodborne pathogens are transmitted and the risks they pose in the workplace.</p><p style=\"text-align: justify;\"> Learners will understand common bloodborne diseases, recognize exposure hazards, and apply OSHA-required infection control practices. The course also covers proper use of personal protective equipment (PPE) and the correct response to exposure incidents. Designed for employers and employees, this training supports workplace safety, regulatory compliance, and effective prevention of occupational health risks.</p>', '[\"Understand what bloodborne pathogens are and how they are transmitted\",\"Identify common bloodborne diseases, including HBV, HCV, and HIV\",\"Recognize workplace exposure risks and hazardous situations\",\"Apply OSHA-required infection control practices effectively\",\"Use personal protective equipment (PPE) correctly and consistently\",\"Follow proper procedures after an exposure incident\"]', '{\"What is Bloodborne Pathogens (BBP) training?\":\"Bloodborne Pathogens (BBP) training educates employees on how diseases carried in blood\\u2014such as HBV, HCV, and HIV\\u2014are transmitted, and how to prevent exposure in the workplace. The training follows OSHA 29 CFR 1910.1030 requirements.\",\"Who is required to take this course?\":\"This course is required for employees who may come into contact with blood or other potentially infectious materials as part of their job duties, including healthcare workers, first responders, custodial staff, and certain industrial workers.\",\"Is this course OSHA compliant?\":\"Yes. This course is fully compliant with OSHA Standard 29 CFR 1910.1030 and meets federal training requirements for Bloodborne Pathogens and Infection Control.\",\"How long is the training?\":\"The total duration of the course is 1 hour, covering essential topics such as exposure risks, infection control practices, PPE use, and response procedures.\",\"What delivery formats are available?\":\"The course is available in Online, Classroom, and Hybrid formats to meet different organizational and scheduling needs.\"}', 'english', 9, 10, '[15]', '[\"No prior experience or certification is required\",\"Participants must be at least 18 years old\",\"Basic understanding of workplace safety is recommended\",\"Access to a computer, tablet, or mobile device (for online training)\",\"Internet connection for online or hybrid delivery formats\"]', 0, NULL, 0, 'intermediate', '70,1,2', NULL, 'https://youtu.be/49JuC99iR68', 1768377600, 1771657857, 'general', 0, 0, 0, 'active', 'youtube', '', 'OSHA-compliant Bloodborne Pathogens and Infection Control training by HRC Service. Learn exposure risks, PPE use, and workplace safety practices.', 1, 1, 1, 70, NULL, NULL, ''),
(9, 'Emergency Evacuation, Fire Safety, and Reporting Training', 'This OSHA-compliant training equips employees with the knowledge needed to respond confidently to emergencies, follow evacuation plans, handle fire-related situations, and report incidents accurately to support workplace safety and compliance.', '<p>This course provides essential training on Emergency Evacuation, Fire Safety, and Incident Reporting in compliance with OSHA 29 CFR 1910.38 (Emergency Action Plans). Delivered by HRC Service, the program prepares employees to respond safely and effectively during workplace emergencies. Participants will learn evacuation procedures, fire prevention and response basics, alarm systems, and proper reporting protocols. Designed for office and industrial environments, the training helps organizations improve emergency preparedness, reduce risk, and maintain OSHA compliance.</p>', '[\"Understand the purpose and importance of an Emergency Action Plan (EAP)\",\"Identify emergency evacuation routes and assembly areas\",\"Recognize fire hazards and basic fire prevention practices\",\"Respond appropriately to fire alarms and emergency alerts\",\"Follow proper emergency reporting and communication procedures\",\"Support a safer workplace and maintain OSHA compliance\"]', '{\"What is this Emergency Evacuation, Fire Safety, and Reporting course?\":\"This course provides OSHA-compliant training on emergency evacuation procedures, fire safety practices, and incident reporting in accordance with OSHA 29 CFR 1910.38 (Emergency Action Plans).\",\"Who should take this course?\":\"All employees who work in office, industrial, or mixed environments and may be required to respond to workplace emergencies should complete this training.\",\"Is this course OSHA compliant?\":\"Yes. The course is designed to meet the requirements of OSHA 29 CFR 1910.38, which governs Emergency Action Plans.\",\"How long does the training take?\":\"The total course duration is 1 hour, covering evacuation procedures, fire safety basics, alarm systems, and reporting responsibilities.\",\"Will participants receive a certificate?\":\"Yes. Participants will receive a certificate of completion after successfully completing the course.\"}', 'english', 9, 11, '[16]', '[\"No prior training or certification is required\",\"Participants must be at least 18 years old\",\"Basic understanding of workplace safety is recommended\",\"Access to a computer, tablet, or mobile device for online training\",\"Internet connection for online or hybrid formats\",\"Completion of the full 1-hour training to receive certification\"]', 0, NULL, 0, 'advanced', '1', NULL, 'https://youtu.be/OdyvNp-3A_4', 1768377600, 1771698805, 'general', 1, 0, 0, 'active', 'youtube', '', 'OSHA 29 CFR 1910.38 compliant Emergency Evacuation, Fire Safety, and Reporting training by HRC Service to support workplace safety and preparedness.', 1, 1, 1, 1, NULL, NULL, ''),
(10, 'Mastering PPE Safety in Just 60 Minutes', 'Looking to master Personal Protective Equipment (PPE) safety in just 60 minutes? This course covers everything you need to know to protect yourself while working in hazardous environments. Learn the importance of PPE, correct selection, proper use, limitations, and best practices to help maintain a safe and compliant workplace.', '<h2 data-start=\"255\" data-end=\"303\"><strong data-start=\"258\" data-end=\"301\">Mastering PPE Safety in Just 60 Minutes</strong></h2><p data-start=\"304\" data-end=\"449\"><strong data-start=\"304\" data-end=\"327\">Standard Reference:</strong> OSHA 29 CFR 1910.132<br data-start=\"348\" data-end=\"351\">\r\n<strong data-start=\"351\" data-end=\"370\">Total Duration:</strong> 60 Minutes<br data-start=\"381\" data-end=\"384\">\r\n<strong data-start=\"384\" data-end=\"394\">Level:</strong> Beginner<br data-start=\"403\" data-end=\"406\">\r\n<strong data-start=\"406\" data-end=\"419\">Delivery:</strong> Online / Classroom / Hybrid</p><h2 data-start=\"456\" data-end=\"523\"><span style=\"font-size: 1.875rem;\">Module 1: Introduction to PPE & Workplace Safety (10 Minutes)</span></h2><ul data-start=\"525\" data-end=\"763\">\r\n<li data-start=\"525\" data-end=\"572\">\r\n<p data-start=\"527\" data-end=\"572\">What is Personal Protective Equipment (PPE)</p>\r\n</li>\r\n<li data-start=\"573\" data-end=\"614\">\r\n<p data-start=\"575\" data-end=\"614\">Importance of PPE in workplace safety</p>\r\n</li>\r\n<li data-start=\"615\" data-end=\"667\">\r\n<p data-start=\"617\" data-end=\"667\">OSHA PPE requirements overview (29 CFR 1910.132)</p>\r\n</li>\r\n<li data-start=\"668\" data-end=\"710\">\r\n<p data-start=\"670\" data-end=\"710\">Employer and employee responsibilities</p>\r\n</li>\r\n<li data-start=\"711\" data-end=\"763\">\r\n<p data-start=\"713\" data-end=\"763\">PPE as part of the overall hazard control system</p>\r\n</li>\r\n</ul><p data-start=\"765\" data-end=\"849\"><strong data-start=\"765\" data-end=\"777\">Outcome:</strong><br data-start=\"777\" data-end=\"780\">\r\nParticipants understand why PPE is critical and when it must be used.</p><hr data-start=\"851\" data-end=\"854\"><h2 data-start=\"856\" data-end=\"924\">Module 2: Hazard Identification & Risk Assessment (10 Minutes)</h2><ul data-start=\"926\" data-end=\"1165\">\r\n<li data-start=\"926\" data-end=\"1058\">\r\n<p data-start=\"928\" data-end=\"959\">Identifying workplace hazards</p>\r\n<ul data-start=\"962\" data-end=\"1058\">\r\n<li data-start=\"962\" data-end=\"982\">\r\n<p data-start=\"964\" data-end=\"982\">Physical hazards</p>\r\n</li>\r\n<li data-start=\"985\" data-end=\"1005\">\r\n<p data-start=\"987\" data-end=\"1005\">Chemical hazards</p>\r\n</li>\r\n<li data-start=\"1008\" data-end=\"1030\">\r\n<p data-start=\"1010\" data-end=\"1030\">Biological hazards</p>\r\n</li>\r\n<li data-start=\"1033\" data-end=\"1058\">\r\n<p data-start=\"1035\" data-end=\"1058\">Environmental hazards</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li data-start=\"1059\" data-end=\"1083\">\r\n<p data-start=\"1061\" data-end=\"1083\">When PPE is required</p>\r\n</li>\r\n<li data-start=\"1084\" data-end=\"1123\">\r\n<p data-start=\"1086\" data-end=\"1123\">Conducting basic hazard assessments</p>\r\n</li>\r\n<li data-start=\"1124\" data-end=\"1165\">\r\n<p data-start=\"1126\" data-end=\"1165\">Matching hazards with appropriate PPE</p>\r\n</li>\r\n</ul><p data-start=\"1167\" data-end=\"1253\"><strong data-start=\"1167\" data-end=\"1179\">Outcome:</strong><br data-start=\"1179\" data-end=\"1182\">\r\nParticipants can recognize hazards and determine when PPE is necessary.</p><hr data-start=\"1255\" data-end=\"1258\"><h2 data-start=\"1260\" data-end=\"1327\">Module 3: Types of Personal Protective Equipment (15 Minutes)</h2><ul data-start=\"1329\" data-end=\"1596\">\r\n<li data-start=\"1329\" data-end=\"1369\">\r\n<p data-start=\"1331\" data-end=\"1369\">Head protection (helmets, hard hats)</p>\r\n</li>\r\n<li data-start=\"1370\" data-end=\"1421\">\r\n<p data-start=\"1372\" data-end=\"1421\">Eye and face protection (goggles, face shields)</p>\r\n</li>\r\n<li data-start=\"1422\" data-end=\"1458\">\r\n<p data-start=\"1424\" data-end=\"1458\">Hand and arm protection (gloves)</p>\r\n</li>\r\n<li data-start=\"1459\" data-end=\"1508\">\r\n<p data-start=\"1461\" data-end=\"1508\">Foot and leg protection (safety shoes, boots)</p>\r\n</li>\r\n<li data-start=\"1509\" data-end=\"1552\">\r\n<p data-start=\"1511\" data-end=\"1552\">Hearing protection (earplugs, earmuffs)</p>\r\n</li>\r\n<li data-start=\"1553\" data-end=\"1596\">\r\n<p data-start=\"1555\" data-end=\"1596\">Respiratory protection (basic overview)</p>\r\n</li>\r\n</ul><p data-start=\"1598\" data-end=\"1689\"><strong data-start=\"1598\" data-end=\"1610\">Outcome:</strong><br data-start=\"1610\" data-end=\"1613\">\r\nParticipants can identify different PPE types and their proper applications.</p><hr data-start=\"1691\" data-end=\"1694\"><h2 data-start=\"1696\" data-end=\"1768\">Module 4: Proper Use, Inspection & Maintenance of PPE (15 Minutes)</h2><ul data-start=\"1770\" data-end=\"1953\">\r\n<li data-start=\"1770\" data-end=\"1812\">\r\n<p data-start=\"1772\" data-end=\"1812\">Correct donning and doffing procedures</p>\r\n</li>\r\n<li data-start=\"1813\" data-end=\"1842\">\r\n<p data-start=\"1815\" data-end=\"1842\">Inspecting PPE before use</p>\r\n</li>\r\n<li data-start=\"1843\" data-end=\"1881\">\r\n<p data-start=\"1845\" data-end=\"1881\">Cleaning, storage, and maintenance</p>\r\n</li>\r\n<li data-start=\"1882\" data-end=\"1922\">\r\n<p data-start=\"1884\" data-end=\"1922\">Recognizing damaged or defective PPE</p>\r\n</li>\r\n<li data-start=\"1923\" data-end=\"1953\">\r\n<p data-start=\"1925\" data-end=\"1953\">PPE replacement guidelines</p>\r\n</li>\r\n</ul><p data-start=\"1955\" data-end=\"2042\"><strong data-start=\"1955\" data-end=\"1967\">Outcome:</strong><br data-start=\"1967\" data-end=\"1970\">\r\nParticipants can correctly use and maintain PPE to ensure effectiveness.</p><hr data-start=\"2044\" data-end=\"2047\"><h2 data-start=\"2049\" data-end=\"2122\">Module 5: PPE Limitations, Best Practices & Compliance (10 Minutes)</h2><ul data-start=\"2124\" data-end=\"2351\">\r\n<li data-start=\"2124\" data-end=\"2164\">\r\n<p data-start=\"2126\" data-end=\"2164\">Understanding the limitations of PPE</p>\r\n</li>\r\n<li data-start=\"2165\" data-end=\"2232\">\r\n<p data-start=\"2167\" data-end=\"2232\">Why PPE does not replace engineering or administrative controls</p>\r\n</li>\r\n<li data-start=\"2233\" data-end=\"2267\">\r\n<p data-start=\"2235\" data-end=\"2267\">Common PPE misuse and mistakes</p>\r\n</li>\r\n<li data-start=\"2268\" data-end=\"2310\">\r\n<p data-start=\"2270\" data-end=\"2310\">Safe work practices and PPE compliance</p>\r\n</li>\r\n<li data-start=\"2311\" data-end=\"2351\">\r\n<p data-start=\"2313\" data-end=\"2351\">Creating a strong PPE safety culture</p>\r\n</li>\r\n</ul><p data-start=\"263\" data-end=\"589\">\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n</p><p data-start=\"2353\" data-end=\"2441\"><strong data-start=\"2353\" data-end=\"2365\">Outcome:</strong><br data-start=\"2365\" data-end=\"2368\">\r\nParticipants apply best practices and understand compliance expectations.</p>', '[\"Understand the role of PPE in preventing workplace injuries\",\"Identify workplace hazards that require PPE\",\"Select the correct PPE for specific job tasks\",\"Use PPE properly, including inspection, donning, and doffing\",\"Recognize the limitations of PPE\",\"Follow workplace safety responsibilities related to PPE\",\"Contribute to a safer and more compliant work environment\"]', '{\"What is PPE Safety training?\":\"PPE Safety training teaches employees how to correctly select, use, and maintain Personal Protective Equipment to reduce exposure to workplace hazards.\",\"Who should take this course?\":\"This course is recommended for employees working in industrial, construction, warehouse, manufacturing, healthcare, or other hazardous environments.\",\"How long is the course?\":\"The total course duration is 60 minutes.\",\"Is this course OSHA compliant?\":\"The course aligns with OSHA PPE safety principles and workplace safety requirements.\",\"Will I receive a certificate?\":\"Yes. A certificate of completion is provided after successfully completing the course.\"}', 'english', 9, 10, '[17]', '[\"No prior safety training or certification is required\",\"Participants must be at least 18 years old\",\"Basic understanding of workplace tasks is recommended\",\"Access to a computer, tablet, or mobile device\",\"Internet connection for online training\",\"Completion of the full 60-minute course to receive a certificate\"]', 0, NULL, 0, 'intermediate', '70,1', NULL, 'https://youtu.be/a04hvjLTPCU', 1768636800, 1771661905, 'general', 1, 0, 0, 'active', 'youtube', '', 'Learn how to properly select, use, and maintain Personal Protective Equipment (PPE) in this 60-minute workplace safety training designed to reduce hazards and injuries.', 1, 1, 1, 70, NULL, NULL, ''),
(11, 'Human Trafficking Awareness Training – Part 1', 'This course provides essential awareness training on human trafficking for hospitality professionals. Participants will learn how trafficking occurs in hotels and hospitality settings, recognize warning signs, and understand their role in prevention and responsible reporting.', '<p data-start=\"682\" data-end=\"1058\"><strong data-start=\"682\" data-end=\"742\" style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">Human Trafficking Awareness for the Hospitality Industry</strong><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\"> is designed to help hotel and hospitality professionals recognize and respond to potential human trafficking situations. Because hotels, motels, and hospitality venues are sometimes misused by traffickers, frontline staff play a critical role in identifying warning signs and helping protect vulnerable individuals.</span></p><p data-start=\"1060\" data-end=\"1484\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">This course explains what human trafficking is, the forms it may take, and why the hospitality industry is uniquely positioned to support prevention efforts. Participants will learn common indicators of trafficking, behavioral red flags, and environmental clues that may signal exploitation. The training also emphasizes safe, appropriate reporting procedures and the importance of following company policies and local laws.</span></p><p data-start=\"1060\" data-end=\"1484\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">This course is suitable for hotel staff, front desk employees, housekeeping, management, security, and other hospitality professionals. By completing this training, participants will gain the knowledge needed to increase awareness, support victim safety, and contribute to a responsible, ethical hospitality environment.</span></p>', '[\"Understand what human trafficking is and how it affects the hospitality industry\",\"Recognize common warning signs and indicators of trafficking in hotel settings\",\"Identify high-risk situations and environments within hospitality operations\",\"Understand employee roles and responsibilities in prevention efforts\",\"Follow proper, safe reporting procedures according to company policy and local laws\",\"Contribute to a safer, more ethical hospitality environment\",\"Support awareness and prevention without putting themselves or others at risk\"]', '{\"What is this course about?\":\"This course provides awareness training on human trafficking specifically for the hospitality industry. It helps employees recognize warning signs, understand risks, and respond appropriately.\",\"Who should take this course?\":\"This course is designed for hotel and hospitality professionals, including front desk staff, housekeeping, management, security personnel, and supervisors.\",\"Is this course mandatory?\":\"While requirements vary by state and organization, many jurisdictions recommend or require human trafficking awareness training for hospitality employees. This course supports compliance and best practices.\",\"Does this course teach how to intervene?\":\"No. The course focuses on awareness, recognition, and safe reporting. Participants are not instructed to intervene directly, ensuring personal and guest safety.\",\"Will I receive a certificate?\":\"Yes. Participants receive a certificate of completion after successfully finishing the course.\"}', 'english', 4, 5, '[24]', '[\"No prior training or experience is required\",\"Participants must be at least 18 years old\",\"Basic understanding of hospitality operations is recommended\",\"Access to a computer, tablet, or mobile device\",\"Internet connection for online delivery\",\"Completion of all course modules to receive certification\"]', 0, NULL, 0, 'beginner', '70,1', NULL, 'https://youtu.be/rz0_vtZJcxA', 1768809600, 1771661944, 'general', 1, 0, 0, 'active', 'youtube', '', 'This hospitality-focused training helps employees identify human trafficking indicators and understand safe, responsible reporting procedures.', 1, 1, 1, 70, NULL, NULL, ''),
(12, 'Human Trafficking Awareness Training – Part 2', 'This course builds on foundational knowledge from Part 1 and focuses on recognizing advanced indicators of human trafficking, understanding reporting responsibilities, and responding appropriately within workplace and community settings.', '<p data-start=\"631\" data-end=\"1014\"><strong data-start=\"631\" data-end=\"680\" style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">Human Trafficking Awareness Training – Part 2</strong><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\"> expands upon the core concepts introduced in Part 1 by focusing on deeper awareness, situational recognition, and responsible action. This course is designed to help participants identify more complex indicators of human trafficking, understand high-risk environments, and recognize patterns of behavior that may signal exploitation.</span></p><p data-start=\"631\" data-end=\"1014\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">Participants will learn the importance of safe, non-confrontational responses and the correct procedures for reporting concerns through internal channels and appropriate authorities. Emphasis is placed on employee responsibility, confidentiality, and personal safety, ensuring that learners understand what to do—and what not to do—when concerns arise.</span></p><p data-start=\"1016\" data-end=\"1368\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">This training is suitable for employees, supervisors, and managers across all industries. By completing Part 2, participants strengthen their ability to support prevention efforts, protect vulnerable individuals, and contribute to a safer, more informed workplace and community.</span></p>', '[\"Identify advanced indicators and patterns of human trafficking\",\"Recognize high-risk situations and environments\",\"Apply awareness skills in workplace and community settings\",\"Understand employee roles and responsibilities in prevention efforts\",\"Follow proper internal and external reporting procedures\",\"Maintain confidentiality and prioritize personal safety\",\"Avoid direct confrontation or intervention\",\"Support organizational compliance and ethical practices\",\"Contribute to a safer, more informed workplace culture\"]', '{\"What is the focus of Part 2?\":\"Part 2 focuses on advanced awareness, recognizing complex trafficking indicators, understanding reporting responsibilities, and responding safely without direct intervention.\",\"Is Part 1 required before taking Part 2?\":\"Yes. Part 1 is recommended as a prerequisite because it provides the foundational knowledge needed to understand the advanced concepts in Part 2.\",\"Who should take this course?\":\"This course is suitable for employees, supervisors, managers, and individuals seeking a deeper understanding of human trafficking awareness and reporting procedures.\",\"Does this course teach how to confront traffickers?\":\"No. This training emphasizes safe, non-confrontational awareness and reporting. Direct intervention is not recommended due to safety risks.\",\"Will this course explain how to report concerns?\":\"Yes. The course explains appropriate internal reporting procedures, when to escalate concerns, and the importance of following company policies and local laws.\",\"Is this course specific to any industry?\":\"No. While examples may reference workplace and community settings, Part 2 is designed for use across all industries.\",\"\\u2753 Does the course include real-world scenarios?\":\"Yes. Part 2 includes scenario-based examples to help learners apply awareness concepts to real-life situations.\",\"How long is this couDoes this course include legal advice?rse?\":\"\\u2753 Does this course include legal advice?\\r\\n\\r\\nAnswer:\\r\\nNo. This course is for awareness and educational purposes only. It does not provide legal advice or replace law enforcement or legal authorities.\\r\\n\\r\\n\\u2753 What should I do if I am unsure whether a situation involves human trafficking?\\r\\n\\r\\nAnswer:\\r\\nIf you are unsure, you should still report your concern through your organization\\u2019s designated reporting channels. It is better to report and allow trained professionals to assess the situation than to ignore potential warning signs.\"}', 'english', 4, 5, '[25]', '[\"Completion of Human Trafficking Awareness Training \\u2013 Part 1 is recommended\",\"Participants must be 18 years or older\",\"No prior law enforcement or investigative experience required\",\"Access to a computer, tablet, or mobile device\",\"Reliable internet connection for online delivery\",\"Completion of all lessons and assessments to receive a certificate\"]', 0, NULL, 0, 'advanced', '70,1', NULL, 'https://youtu.be/CDIdwqsU6gg', 1768809600, 1771662079, 'general', 1, 0, 0, 'active', 'youtube', '', 'Human trafficking awareness training for hospitality professionals. Learn to recognize warning signs and follow safe reporting practices.', 1, 1, 1, 70, NULL, NULL, ''),
(13, 'HIPAA Compliance Training: Privacy & Security Essentials Certification | HRC Service', 'Learn the essential privacy and security requirements of HIPAA and protect sensitive health information with this professional certification course from HRC Service.', '<p><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">Healthcare organizations and their business associates are required to protect sensitive patient information under the Health Insurance Portability and Accountability Act (HIPAA).</span></p><p><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">The HIPAA Compliance Training: Privacy & Security Essentials Certification course by HRC Service provides a clear and practical understanding of HIPAA regulations, privacy rules, and security safeguards.</span></p><p><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">This course is designed for healthcare professionals, administrative staff, HR personnel, compliance officers, and business associates who handle protected health information (PHI).</span></p><h3>In this training, you will learn:</h3><p><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">• The fundamentals of HIPAA regulations</span></p><p><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">• Understanding Protected Health Information (PHI)</span></p><p><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">• HIPAA Privacy Rule requirements</span></p><p><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">• HIPAA Security Rule safeguards</span></p><p><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">• Administrative, physical, and technical protections</span></p><p><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">• Breach notification requirements</span></p><p><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">• Employee responsibilities and best practices</span></p><p><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">• Preventing common HIPAA violations</span></p><p><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">Our structured and easy-to-follow format ensures learners gain practical knowledge that can be immediately applied in the workplace.</span></p><p><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">Upon successful completion, participants will receive a certification of completion from HRC Service.</span></p><p><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">Protect patient data. Strengthen compliance. Reduce risk.</span></p><p><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">Enroll today and ensure your organization stays compliant with HIPAA privacy and security standards.</span></p>', '[\"\\u2022 Understand the fundamentals of HIPAA regulations\",\"\\u2022 Identify Protected Health Information (PHI)\",\"\\u2022 Apply HIPAA Privacy Rule requirements\",\"\\u2022 Implement basic Security Rule safeguards\",\"\\u2022 Recognize and prevent common HIPAA violations\",\"\\u2022 Understand breach notification responsibilities\",\"\\u2022 Strengthen workplace compliance practices\"]', '{\"What is HIPAA compliance training?\":\"HIPAA compliance training teaches healthcare professionals and business associates how to protect Protected Health Information (PHI) and follow federal privacy and security regulations.\",\"Who should take this course?\":\"This course is designed for healthcare professionals, administrative staff, HR teams, compliance officers, and any employee who handles patient information.\",\"Does this course provide certification?\":\"Yes. Upon successful completion, participants will receive a HIPAA Compliance Certification from HRC Service.\",\"How long does the training take?\":\"The course is designed to be completed within approximately 1 hour, depending on the learner\\u2019s pace.\",\"Is this course suitable for annual HIPAA training?\":\"Yes. This course supports annual HIPAA training requirements for healthcare organizations and business associates.\"}', 'english', 9, 10, '[27]', '[\"\\u2022 No prior HIPAA knowledge required\",\"\\u2022 Basic understanding of healthcare or workplace compliance is helpful\",\"\\u2022 Access to a computer, tablet, or mobile device\",\"\\u2022 Internet connection\"]', 0, NULL, 0, 'intermediate', '70,1', NULL, 'https://youtu.be/OqXlnI-FUf0', 1771574400, 1771781818, 'general', 1, 0, 0, 'active', 'youtube', '', 'Professional HIPAA Compliance Training covering Privacy & Security Essentials. Learn HIPAA regulations, protect patient data, ensure healthcare compliance, and strengthen data security with this comprehensive online certification course.', 1, 1, 0, 70, NULL, NULL, ''),
(14, 'HRC Service Anti Discrimination &amp; Anti Harassment Workplace Training', 'Learn the essentials of Anti-Harassment Workplace Training and create a respectful, compliant work environment. This employee compliance course covers key policies, real scenarios, and best practices for maintaining professionalism at work.\r\n\r\n', '<p><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">Anti-Harassment Workplace Training – Employee Compliance Course</span></p><p><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">Creating a safe, respectful, and inclusive workplace is essential for every organization. The Anti-Harassment Workplace Training course is designed to help employees understand workplace harassment, recognize inappropriate behavior, and learn how to prevent and respond to it effectively.</span></p><p><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">This course provides clear guidance on company policies, legal responsibilities, and professional conduct in the workplace. Through practical examples and real-world scenarios, employees will gain the knowledge and confidence needed to promote a respectful work environment and support a positive organizational culture.</span></p><p><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">Participants will learn how to identify different forms of harassment, understand reporting procedures, and contribute to maintaining a workplace where everyone feels safe and valued.</span></p><p><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\"><b>What You Will Learn</b></span></p><ol><li><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">Understanding workplace harassment and discrimination</span></li><li><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">Types of harassment and inappropriate workplace behavior</span></li><li><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">Employee rights and responsibilities</span></li><li><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">How to report harassment safely and confidentially</span></li><li><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">Building a respectful and inclusive workplace culture</span></li><li><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">Company policies and compliance requirements</span></li></ol><p><b style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">Who This Course Is For</b></p><ol><li><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">Employees at all levels</span></li><li><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">HR professionals and managers</span></li><li><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">Team leaders and supervisors</span></li><li><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">Organizations implementing workplace compliance training</span></li></ol><p><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">By completing this training, employees will be better equipped to recognize, prevent, and address harassment, ensuring a professional and respectful workplace for everyone.</span></p>', '[\"By the end of this Anti-Harassment Workplace Training, participants will be able to:\",\"Understand workplace harassment and recognize different types of inappropriate behavior.\",\"Identify situations that may lead to harassment or discrimination in the workplace.\",\"Apply company policies and compliance guidelines related to workplace conduct.\",\"Respond appropriately to harassment incidents and understand the proper reporting procedures.\",\"Promote a respectful, safe, and inclusive workplace environment.\",\"Support a positive workplace culture based on professionalism, respect, and accountability.\",\"Understand employee rights and responsibilities regarding workplace behavior.\"]', '{\"1. What is Anti-Harassment Workplace Training?\":\"Anti-Harassment Workplace Training is a compliance course designed to help employees understand workplace harassment, recognize inappropriate behavior, and learn how to prevent and report harassment in a professional environment.\",\"2. Who should take this course?\":\"This course is recommended for all employees, managers, supervisors, and HR professionals who want to maintain a respectful and safe workplace.\",\"3. Why is anti-harassment training important?\":\"Anti-harassment training helps create a safe, respectful, and inclusive work environment, reduces workplace conflicts, and ensures organizations comply with legal and company policies.\",\"4. What topics are covered in this course?\":\"The course covers:\\r\\n\\r\\nTypes of workplace harassment\\r\\nRecognizing inappropriate workplace behavior\\r\\nEmployee rights and responsibilities\\r\\n\\r\\nReporting procedures and company policies\\r\\n\\r\\nBuilding a respectful workplace culture\",\"5. How long does the course take to complete?\":\"The course typically takes 30\\u201360 minutes, depending on the learning format and additional activities included.\",\"6. Do participants receive a certificate after completing the course?\":\"Yes, participants receive a certificate of completion after successfully finishing the training.\",\"7. Is this course suitable for managers and supervisors?\":\"Yes. Managers and supervisors will learn how to identify harassment, handle complaints properly, and maintain a compliant workplace environment.\",\"8. Is this course compliant with workplace regulations?\":\"The course is designed to align with standard workplace compliance and HR best practices related to harassment prevention.\",\"9. Can this training be taken online?\":\"Yes, the course can be delivered online, in-person, or as part of an e-learning program.\",\"10. How does this training benefit organizations?\":\"Organizations benefit by reducing workplace risk, improving company culture, promoting professionalism, and ensuring legal compliance.\"}', 'english', 9, 10, '[]', '[\"Basic understanding of workplace professional conduct\",\"Willingness to learn about respectful and inclusive workplace behavior\",\"Access to a computer, tablet, or smartphone for online training\",\"Internet connection for viewing course materials and videos\",\"Ability to understand basic workplace communication and policies\"]', 0, NULL, 0, 'advanced', '70', NULL, 'https://youtu.be/rkEy2rp3fvY', 1772697600, NULL, 'general', 1, 0, 0, 'active', 'youtube', '', 'Anti-Harassment Workplace Training course designed to help employees understand workplace harassment, company policies, and reporting procedures. Learn how to create a respectful, safe, and compliant work environment.', 1, 0, 1, 70, NULL, NULL, ''),
(15, 'California Sexual Harassment Prevention Training | Mandatory Compliance Course (AB 1825 / SB 1343)', 'Stay compliant with California law \r\nLearn sexual harassment prevention and abusive conduct training required under CA Gov’t Code §12950.1. This training is mandatory for employers with 5+ employees.\r\n✔ Non-Supervisors: 1 Hour\r\n✔ Required every 2 years\r\n', '<p data-start=\"420\" data-end=\"459\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">Stay compliant with California law </span></p><p data-start=\"461\" data-end=\"623\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">Learn sexual harassment prevention and abusive conduct training required under CA Gov’t Code §12950.1. This training is mandatory for employers with 5+ employees.</span></p><p data-start=\"461\" data-end=\"623\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">✔ Non-Supervisors: 1 Hour</span></p><p data-start=\"461\" data-end=\"623\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">✔ Required every 2 years</span></p><p>\r\n\r\n\r\n</p><p data-start=\"706\" data-end=\"769\"><br></p>', '[\"Understand the key requirements of California Sexual Harassment Prevention laws (AB 1825 & SB 1343)\",\"Identify different forms of workplace harassment, discrimination, and abusive conduct\",\"Recognize inappropriate behavior, including subtle and indirect harassment\",\"Recognize inappropriate behavior, including subtle and indirect harassment\",\"Apply best practices to prevent harassment and promote a respectful workplace\",\"Respond appropriately to harassment situations as an employee or supervisor\",\"Follow proper reporting procedures and understand employee rights\",\"Demonstrate responsibility in maintaining a safe, inclusive, and compliant work environment\",\"Reduce legal risks by adhering to workplace policies and regulations\",\"Contribute to a positive workplace culture built on respect, integrity, and professionalism\"]', '{\"1. Who is required to take this training?\":\"This training is mandatory for all employees working in California organizations with 5 or more employees, including full-time, part-time, temporary, seasonal workers, and independent contractors.\",\"2. How long is the training?\":\"Non-Supervisors: 1 hour\",\"3. How often do I need to complete this training?\":\"Employees must complete this training:\\r\\nWithin 6 months of hire or promotion, and\\r\\nEvery 2 years thereafter\",\"4. Are seasonal or temporary employees required to complete this training?\":\"Yes. Seasonal or temporary employees must complete training within:\\r\\n\\r\\n30 days of hire, or 100 hours worked, whichever comes first.\",\"5. What topics are covered in this course?\":\"This training includes:\\r\\n\\r\\nSexual harassment prevention\\r\\nAbusive conduct (bullying)\\r\\nWorkplace discrimination\\r\\nGender identity and gender expression\\r\\nSexual orientation awareness\\r\\nReporting procedures and employee rights\",\"6. Is this course compliant with California law?\":\"Yes. This course is fully compliant with:qa\\r\\nCA Gov\\u2019t Code \\u00a712950.1 (AB 1825 \\/ SB 1343)\",\"7. What will I learn from this training?\":\"You will learn how to:\\r\\n\\r\\nIdentify harassment and inappropriate behavior\\r\\nPrevent workplace misconduct\\r\\nRespond appropriately to incidents\\r\\nMaintain a respectful and inclusive workplace\"}', 'english', 4, 5, '[]', '[\"No prior experience or training is required.\",\"Basic understanding of workplace behavior is helpful but not mandatory.\",\"Basic understanding of workplace behavior is helpful but not mandatory.\",\"Ability to understand and follow English language instructions.\",\"Commitment to complete the full training duration (1 hour for non-supervisors \\/ 2 hours for supervisors).\",\"Commitment to complete the full training duration (1 hour for non-supervisors \\/ 2 hours for supervisors).\",\"Required for employees working in California under applicable law (CA Gov\\u2019t Code \\u00a712950.1).\"]', 0, NULL, 0, 'advanced', '70,1', NULL, 'https://youtu.be/suGNcgBbPUU', 1775113200, 1775157884, 'general', 1, 0, 0, 'active', 'youtube', '', 'California Mandatory Training: Sexual Harassment Prevention course designed to help employees understand workplace harassment laws, compliance requirements, and reporting procedures. Learn how to create a safe, respectful, and legally compliant workplace environment.', 1, 1, 0, 70, NULL, NULL, ''),
(18, 'The Complete Guide to FLSA, PTO, and Workforce Security', 'The Complete Guide to FLSA, PTO, and Workforce Security\r\n', '<p><ytd-badge-supported-renderer class=\"style-scope ytd-watch-metadata\" system-icons=\"\" style=\"display: flex; flex-direction: row; align-items: center; color: rgb(241, 241, 241); font-family: Roboto, Arial, sans-serif; font-size: 10px; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; background-color: rgb(15, 15, 15); text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\"><yt-badge-supported-renderer class=\"ytBadgeSupportedRendererHost\" style=\"display: flex; align-items: center;\"></yt-badge-supported-renderer></ytd-badge-supported-renderer></p><div class=\"badge-shape ytBadgeSupportedRendererBadgeShape\" style=\"margin: 0px 4px 0px 0px; padding: 0px; border: 0px; background: transparent;\"><yt-metadata-badge-renderer class=\"ytMetadataBadgeRendererHost\"><badge-shape class=\"ytBadgeShapeHost ytBadgeShapeDefault ytBadgeShapeTypography\" role=\"img\" aria-label=\"AI: Content was made with AI\" style=\"display: flex; flex-direction: row; align-items: center; border-radius: 2px; padding: 0px 4px; font-family: Roboto, Arial, sans-serif; font-size: 1.2rem; line-height: 1.8rem; font-weight: 500; color: rgb(170, 170, 170); background: none 0% 0% / auto repeat scroll padding-box border-box rgba(255, 255, 255, 0.1);\"><div class=\"ytBadgeShapeIcon\" style=\"margin: 0px 2px 0px 0px; padding: 0px; border: 0px; background: transparent; display: block; height: 16px; width: 16px;\"><span class=\"yt-icon-shape ytSpecIconShapeHost\" style=\"margin: 0px; padding: 0px; border: 0px; background: transparent; display: flex; align-items: center; justify-content: center; width: 16px; hei