INSERT INTO `ebook` (`ebook_id`, `user_id`, `category_id`, `title`, `description`, `thumbnail`, `banner`, `file`, `publication_name`, `edition`, `discount_flag`, `discounted_price`, `price`, `added_date`, `updated_date`, `is_active`, `is_free`, `preview`, `no_of_pages`, `meta_title`, `meta_description`, `meta_keywords`, `og_title`, `og_description`, `json_ld`) VALUES
(1, 70, 1, 'Human Trafficking Awareness: Professional Compliance Training for the Hospitality Industry', '&lt;p class=&quot;isSelectedEnd&quot;&gt;&lt;span style=&quot;color: rgb(0, 0, 0); font-size: 0.875rem;&quot;&gt;Human trafficking remains one of the most significant risks facing the hospitality industry today. Hotels, motels, resorts, and lodging facilities are often targeted due to high guest turnover, privacy expectations, and complex workforce environments.&lt;/span&gt;&lt;/p&gt;&lt;p class=&quot;isSelectedEnd&quot;&gt;&lt;span style=&quot;color: rgb(0, 0, 0); font-size: 0.875rem;&quot;&gt;This comprehensive training guide helps hospitality professionals understand the warning signs of human trafficking, identify operational risk factors, strengthen compliance programs, and implement safe reporting procedures.&lt;/span&gt;&lt;/p&gt;&lt;p class=&quot;isSelectedEnd&quot;&gt;&lt;span style=&quot;color: rgb(0, 0, 0); font-size: 0.875rem;&quot;&gt;Inside this guide, readers will learn:&lt;/span&gt;&lt;/p&gt;&lt;h5 class=&quot;dropdown-item&quot;&gt;&lt;b style=&quot;background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);&quot;&gt;• Understanding Human Trafficking and Modern Slavery&lt;br&gt;&lt;/b&gt;&lt;b style=&quot;background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);&quot;&gt;• Hospitality Industry Risk Factors&lt;br&gt;&lt;/b&gt;&lt;b style=&quot;background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);&quot;&gt;• Environmental Indicators and Warning Signs&lt;br&gt;&lt;/b&gt;&lt;b style=&quot;background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);&quot;&gt;• Workforce and Staffing Risks&lt;br&gt;&lt;/b&gt;&lt;b style=&quot;background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);&quot;&gt;• Supply Chain Protection Strategies&lt;br&gt;&lt;/b&gt;&lt;b style=&quot;background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);&quot;&gt;• Safe Reporting Procedures&lt;br&gt;&lt;/b&gt;&lt;b style=&quot;background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);&quot;&gt;• Employee Education and Awareness Programs&lt;br&gt;&lt;/b&gt;&lt;b style=&quot;background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);&quot;&gt;• Emergency Resources and Hotline Information&lt;br&gt;&lt;/b&gt;&lt;b style=&quot;background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);&quot;&gt;• Building a Resilient and Compliant Business&lt;/b&gt;&lt;/h5&gt;&lt;p class=&quot;isSelectedEnd&quot;&gt;&lt;span style=&quot;color: rgb(0, 0, 0); font-size: 0.875rem;&quot;&gt;Designed for hotel owners, hospitality executives, HR professionals, compliance officers, operations managers, and frontline staff, this resource provides practical knowledge to help protect guests, employees, and organizations from trafficking-related risks.&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;color: rgb(0, 0, 0); font-size: 0.875rem;&quot;&gt;Published by HRC Service, a trusted workforce compliance and operational consulting partner for the hospitality industry.&lt;/span&gt;&lt;/p&gt;', 'e4a298385afd1ab631157442deac3720.png', 'placeholder.png', '82dfea49c79ce0348067617c557542e8.pdf', 'HRC Service Professional Compliance Series', 'First Edition 2026', 0, 0, 0, '1780099200', NULL, 1, 1, '71851031d74d8dbe187da62b792ca07f.pdf', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(2, 70, 1, 'test', '&lt;p&gt;text&lt;/p&gt;', '2d394157d6c8de8cf3b56d4819e32937.png', 'placeholder.png', '5b3e01438007810149fd5df472caada9.pdf', 'HRC Service Professional Compliance Series', 'First Edition 2026', 0, 0, 0, '1781560800', NULL, 1, 1, '7999f38c4a74842259d82bab46d0607c.pdf', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
