INSERT INTO `frontend_settings` (`id`, `key`, `value`) VALUES
(1, 'banner_title', 'Complementary Mandatory Training!! '),
(2, 'banner_sub_title', 'Learn with us a range of human resources training'),
(4, 'about_us', '<p></p><h3><span style=\"font-size: 1.5rem;\">About us</span></h3><h2><span xss=\"removed\" style=\"font-weight: normal;\"><h3 style=\"box-sizing: inherit; margin-right: 0px; margin-bottom: 20px; margin-left: 0px; color: rgb(121, 120, 120);\"></h3><h4><span style=\"box-sizing: inherit; margin-bottom: 0px;\"><span style=\"font-family: Arial;\">We believe in a simple philosophy</span><em style=\"box-sizing: inherit;\"><span style=\"font-family: Arial;\">: \"take care of your employees the same way you want them to take care of your customers\"</span></em><em style=\"box-sizing: inherit; margin-bottom: 0px;\"><span style=\"font-family: Helvetica;\"><span style=\"font-family: Arial;\"> </span><br></span></em></span></h4><h4><span style=\"font-family: Arial;\">We aim to create a positive and rewarding environment where employees come to the workplace with a desire to do their best and bring innovative ideas that will enhance the business. In the ever-changing world of laws and regulations, this can create quite the daunting task for the employer. In turn, the employers time is often taken away from being able to focus on the core of the business. HRC is here to demystify the constant changing rules and regulations placed on employers and provide rapidly executed and sound solutions.</span></h4></span></h2>'),
(10, 'terms_and_condition', '<h2>Terms and Conditions </h2><p><span style=\"font-size:12px\" ;=\"\"><b>Terms and Conditions</b></span>\r\n<br><br><span style=\"font-size:12px\" ;=\"\">1. Introduction</span>\r\n<br><span style=\"font-size:12px\" ;=\"\">Welcome to LMS.hrchr.com. These Terms and Conditions govern your access to and use of our Learning Management System (LMS) platform. By using this platform, you agree to comply with these terms. If you do not agree, you must not use the platform.</span>\r\n<br><span style=\"font-size:12px\" ;=\"\">2. Eligibility</span>\r\n<br><span style=\"font-size:12px\" ;=\"\">To use LMS.hrchr.com, you must be at least 18 years old or have parental/guardian consent. You must also provide accurate, current, and complete information when registering.</span>\r\n<br><span style=\"font-size:12px\" ;=\"\">3. User Accounts</span>\r\n<br><span style=\"font-size:12px\" ;=\"\">Account Creation: To access courses and services, users are required to create an account. You are responsible for maintaining the confidentiality of your account credentials and for all activities that occur under your account.</span>\r\n<br><span style=\"font-size:12px\" ;=\"\">Account Security: LMS.hrchr.com reserves the right to suspend or terminate accounts in the event of unauthorized access, suspicious activity, or breaches of these terms.</span><br>\r\n<br><span style=\"font-size:12px\" ;=\"\">4. Use of the Platform</span>\r\n<br><span style=\"font-size:12px\" ;=\"\">Permitted Use: Users are permitted to access the platform for personal or business learning purposes. You must not misuse the platform by disrupting its functionality, accessing areas unauthorized to you, or introducing harmful software.</span>\r\n<br><span style=\"font-size:12px\" ;=\"\">Prohibited Use: The following are strictly prohibited:</span>\r\n<br><span style=\"font-size:12px\" ;=\"\">Sharing your login details with unauthorized users</span>\r\n<br><span style=\"font-size:12px\" ;=\"\">Reselling, redistributing, or sublicensing platform content</span>\r\n<br><span style=\"font-size:12px\" ;=\"\">Using the LMS to upload or distribute unlawful, abusive, or harmful content</span><br></p><p><span style=\"font-size:12px\" ;=\"\">5. Course Access and Availability</span>\r\n<br><span style=\"font-size:12px\" ;=\"\">Enrollment: Upon successful enrollment, users will be granted access to the purchased courses. LMS.hrchr.com reserves the right to alter, update, or remove course content at its discretion.</span>\r\n<br><span style=\"font-size:12px\" ;=\"\">Course Expiration: Access to certain courses may expire after a specific duration. Users must complete courses within this period or repurchase to regain access.</span><br><span style=\"font-size:12px\" ;=\"\">6. Payments and Refunds</span>\r\n<br><span style=\"font-size:12px\" ;=\"\">Pricing: The prices of courses are displayed clearly on the platform. LMS.hrchr.com reserves the right to change pricing at any time.</span>\r\n<br><span style=\"font-size:12px\" ;=\"\">Payments: Payments must be made via approved methods on the platform.</span>\r\n<br><span style=\"font-size:12px\" ;=\"\">Refunds: Refunds are available under certain circumstances (e.g., technical issues that prevent access to a course). All refund requests must be submitted within 14 days of purchase.</span><br><span style=\"font-size:12px\" ;=\"\">7. Intellectual Property</span>\r\n<br><span style=\"font-size:12px\" ;=\"\">Content Ownership: All content available on LMS.hrchr.com, including course material, images, videos, and software, is the intellectual property of LMS.hrchr.com or its licensors.</span>\r\n<br><span style=\"font-size:12px\" ;=\"\">License to Use: Users are granted a limited, non-exclusive license to access the content for personal learning. No ownership rights are transferred to you.</span>\r\n<br><span style=\"font-size:12px\" ;=\"\">Prohibited Actions: You are prohibited from copying, distributing, modifying, or creating derivative works from the platform’s content without explicit permission.</span><br><span style=\"font-size:12px\" ;=\"\">8. Data Privacy and Security</span>\r\n<br><span style=\"font-size:12px\" ;=\"\">Data Collection: LMS.hrchr.com collects and processes personal data in accordance with its Privacy Policy. By using the platform, you consent to this collection and processing.</span>\r\n<br><span style=\"font-size:12px\" ;=\"\">User Security: We implement appropriate security measures to protect user data. However, no system is completely secure, and we cannot guarantee the absolute security of your information.</span><br><span style=\"font-size:12px\" ;=\"\">9. Third-Party Services</span>\r\n<br><span style=\"font-size:12px\" ;=\"\">LMS.hrchr.com may contain links to third-party websites or services. We are not responsible for the content, policies, or practices of these third-party services. Your use of third-party services is at your own risk.</span>\r\n<br><span style=\"font-size:12px\" ;=\"\">10. Limitation of Liability</span>\r\n<br><span style=\"font-size:12px\" ;=\"\">No Warranties: LMS.hrchr.com provides its services on an “as is” basis without warranties of any kind. We do not guarantee the availability, accuracy, or completion of courses.</span>\r\n<br><span style=\"font-size:12px\" ;=\"\">Liability Limit: LMS.hrchr.com shall not be liable for any indirect, consequential, or punitive damages resulting from the use or inability to use the platform.</span><br><span style=\"font-size:12px\" ;=\"\">11. Termination</span>\r\n<br><span style=\"font-size:12px\" ;=\"\">Termination by User: You may terminate your account at any time by notifying LMS.hrchr.com. All outstanding fees will still apply.</span>\r\n<br><span style=\"font-size:12px\" ;=\"\">Termination by LMS.hrchr.com: We reserve the right to suspend or terminate access for users who violate these terms or engage in misconduct on the platform.</span><br><span style=\"font-size:12px\" ;=\"\">12. Modifications to Terms</span>\r\n<br><span style=\"font-size:12px\" ;=\"\">LMS.hrchr.com reserves the right to modify these Terms and Conditions at any time. We will notify users of significant changes via email or within the platform. Your continued use of the platform after any changes indicates acceptance of the revised terms.</span>\r\n<br><span style=\"font-size:12px\" ;=\"\">13. Governing Law</span>\r\n<br><span style=\"font-size:12px\" ;=\"\">These Terms and Conditions are governed by and construed in accordance with the laws of State of California and the United States of America.</span>\r\n<br><span style=\"font-size:12px\" ;=\"\">14. Contact Information</span>\r\n<br><span style=\"font-size:12px\" ;=\"\">For questions or concerns regarding these Terms and Conditions, please contact us at:</span>\r\n<br><br><span style=\"font-size:12px\" ;=\"\">Email: support@hrchr.com</span><br>\r\n<span style=\"font-size:12px\" ;=\"\">Phone: 818-920-6000</span><br><br><!--/data/user/0/com.samsung.android.app.notes/files/clipdata/clipdata_bodytext_240926_160638_947.sdocx--></p>'),
(11, 'privacy_policy', '<p></p><p></p><h2><span xss=\"removed\">Privacy Policy</span></h2><p class=\"MsoNormal\"><o:p> </o:p><span style=\"text-align: center; color: rgb(0, 0, 0); font-size: 0.875rem;\">Privacy Policy for\r\nHRC LMS System</span></p><p class=\"MsoNormal\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">At LMS.HRCHR, we take the privacy of our users seriously and\r\nare committed to protecting your personal information. This Privacy Policy\r\noutlines how we collect, use, and protect your data in compliance with\r\napplicable US privacy laws, including the California Consumer Privacy Act\r\n(CCPA) and General Data Protection Regulation (GDPR) principles.</span></p><p class=\"MsoNormal\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\"># 1. Information We Collect</span></p><p class=\"MsoNormal\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">We collect personal information necessary to provide our Learning\r\nManagement System (LMS) services, including but not limited to:</span></p><p class=\"MsoNormal\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">- Personal Data: Name, email address, company name, and job\r\ntitle.</span></p><p class=\"MsoNormal\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">- Training Data: Course enrollment details, quiz scores,\r\ncertificates, and participation records.</span></p><p class=\"MsoNormal\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">We also collect non-personal data such as browser type, IP\r\naddress, and usage statistics for system performance improvements.</span></p><p class=\"MsoNormal\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\"># 2. How We Use Your Information</span></p><p class=\"MsoNormal\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">We use the information collected for the following purposes:</span></p><p class=\"MsoNormal\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">- To deliver and manage training courses.</span></p><p class=\"MsoNormal\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">- To track course progress and quiz results.</span></p><p class=\"MsoNormal\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">- To issue certifications upon course completion.</span></p><p class=\"MsoNormal\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">- To communicate updates or system-related notifications.</span></p><p class=\"MsoNormal\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">We do not sell, share, or rent your personal information to\r\nthird parties without your explicit consent unless required by law.</span></p><p class=\"MsoNormal\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\"># 3. Data Security</span></p><p class=\"MsoNormal\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">We implement industry-standard security measures to protect\r\nyour data, including encryption, firewalls, and secure access protocols. While\r\nwe strive to protect your information, no method of transmission over the\r\nInternet or method of electronic storage is 100% secure.</span></p><p class=\"MsoNormal\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\"># 4. Your Rights</span></p><p class=\"MsoNormal\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">You have the right to:</span></p><p class=\"MsoNormal\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">- Access the personal information we collect about you.</span></p><p class=\"MsoNormal\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">- Request corrections to any inaccurate data.</span></p><p class=\"MsoNormal\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">- Request deletion of your data, subject to legal\r\nobligations.</span></p><p class=\"MsoNormal\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">- Opt-out of receiving promotional communications.</span></p><p class=\"MsoNormal\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">To exercise these rights, contact us at [Insert Contact\r\nEmail].</span></p><p class=\"MsoNormal\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\"># 5. Data Retention</span></p><p class=\"MsoNormal\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">We retain your personal data only for as long as necessary\r\nto fulfill the purposes outlined in this policy or as required by law.\r\nAfterward, your data will be securely deleted.</span></p><p class=\"MsoNormal\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\"># 6. Legal Compliance</span></p><p class=\"MsoNormal\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">We comply with applicable US privacy regulations, including:</span></p><p class=\"MsoNormal\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">- California Consumer Privacy Act (CCPA): Rights to access\r\nand delete personal information for California residents.</span></p><p class=\"MsoNormal\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">- Children’s Online Privacy Protection Act (COPPA): We do\r\nnot knowingly collect data from children under 13.</span></p><p class=\"MsoNormal\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\"># 7. Changes to this Policy</span></p><p class=\"MsoNormal\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">We may update this Privacy Policy from time to time. Any\r\nchanges will be posted on this page with the updated effective date.</span></p><p class=\"MsoNormal\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\"># Contact Us</span></p><p class=\"MsoNormal\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">For any questions regarding this Privacy Policy, please\r\ncontact us at:</span></p><p class=\"MsoNormal\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">Email: info@hrcservice.com</span></p><p class=\"MsoNormal\"><span style=\"color: rgb(0, 0, 0); font-size: 0.875rem;\">Phone: 818-920-6000</span></p><p><span xss=\"removed\">\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n</span></p><p class=\"MsoNormal\"><o:p> </o:p></p>'),
