INSERT INTO `lesson` (`id`, `title`, `duration`, `course_id`, `section_id`, `video_type`, `cloud_video_id`, `video_url`, `audio_url`, `date_added`, `last_modified`, `lesson_type`, `attachment`, `attachment_type`, `caption`, `summary`, `is_free`, `order`, `quiz_attempt`, `video_type_for_mobile_application`, `video_url_for_mobile_application`, `duration_for_mobile_application`) VALUES
(6, 'Workplace Violence Prevention Training', '00:05:32', 4, 5, 'YouTube', NULL, 'https://youtu.be/sukk2G-e8ZY?si=cM4hBLl6yzbccmlY', NULL, 1726470000, 1779519600, 'video', '', 'url', NULL, '&lt;p style=&quot;text-align: justify; &quot;&gt;&lt;span style=&quot;color: rgb(0, 0, 0); font-size: 0.875rem;&quot;&gt;California Sexual Harassment Prevention Training is designed to educate employees and supervisors about workplace harassment, discrimination, and respectful professional behavior. &lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;text-align: justify; &quot;&gt;&lt;span style=&quot;color: rgb(0, 0, 0); font-size: 0.875rem;&quot;&gt;The course covers California state laws, employee rights, reporting procedures, retaliation prevention, and strategies for maintaining a safe and inclusive work environment. Participants learn how to identify inappropriate conduct, respond effectively to complaints, and promote workplace professionalism. &lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;text-align: justify; &quot;&gt;&lt;span style=&quot;color: rgb(0, 0, 0); font-size: 0.875rem;&quot;&gt;This training helps organizations comply with California legal requirements while fostering a culture of respect, equality, and accountability. The program is suitable for both employees and management staff seeking to improve workplace awareness and prevent harassment-related issues&#039;&lt;/span&gt;&lt;span style=&quot;color: rgb(0, 0, 0); font-size: 0.875rem;&quot;&gt;&amp;nbsp;Video&lt;/span&gt;&lt;/p&gt;', 1, 0, 0, 'html5', 'https://www.html5rocks.com/en/tutorials/video/basics/devstories.webm', '00:05:32'),
(7, 'WPVPT', '0:00:00', 4, 5, NULL, NULL, NULL, NULL, 1726470000, 1726556400, 'quiz', '{\"total_marks\":\"7\",\"pass_mark\":\"6\",\"drip_content_for_passing_rule\":\"not_applicable\"}', 'json', NULL, '', 0, 0, 0, NULL, NULL, NULL),
(10, 'WPVPT- Spanish', '0:00:00', 5, 11, NULL, NULL, NULL, NULL, 1726556400, NULL, 'quiz', '{\"total_marks\":\"7\",\"pass_mark\":\"6\",\"drip_content_for_passing_rule\":\"applicable\"}', 'json', NULL, 'Spanish Quiz', 0, 2, 0, NULL, NULL, NULL),
(11, ' Capacitación para la Prevención de la Violencia en el Lugar de Trabajo', '00:05:58', 5, 11, 'YouTube', NULL, 'https://youtu.be/DNkQx1rLUYk?si=DgPMZY1gjkwOSQeS', NULL, 1726642800, 1731744000, 'video', '', 'url', NULL, '&lt;p&gt;Spanish&lt;/p&gt;', 1, 1, 0, 'html5', 'https://www.html5rocks.com/en/tutorials/video/basics/devstories.webm', '00:01:10'),
(18, 'Bloodborne Pathogens (BBP) &amp; Infection Control', '00:54:18', 8, 15, 'YouTube', NULL, 'https://youtu.be/49JuC99iR68', NULL, 1768377600, 1768723200, 'video', '', 'url', NULL, '&lt;p&gt;The Bloodborne Pathogens (BBP) &amp; Infection Control course provides essential OSHA-compliant training aligned with OSHA 29 CFR 1910.1030. Delivered by HRC Service, this one-hour program educates participants on how bloodborne pathogens are transmitted and the risks they pose in the workplace. &lt;/p&gt;&lt;p&gt;The course covers common bloodborne diseases, exposure risks, infection control practices, proper use of personal protective equipment (PPE), and required procedures following an exposure incident. Designed for employers and employees, this training supports workplace safety, regulatory compliance, and effective prevention of occupational health hazards.&lt;/p&gt;', 0, 0, 0, 'html5', 'https://www.html5rocks.com/en/tutorials/video/basics/devstories.webm', '00:01:10'),
(20, 'Bloodborne Pathogens (BBP) &amp; Infection Control – Final Quiz', '0:15:00', 10, 17, NULL, NULL, NULL, NULL, 1768636800, 1768636800, 'quiz', '{\"total_marks\":\"50\",\"pass_mark\":\"35\",\"drip_content_for_passing_rule\":\"not_applicable\"}', 'json', NULL, 'Answer all questions carefully. Each question carries 5 marks.\r\nA minimum score of 35 out of 50 (70%) is required to pass this quiz.\r\nThis assessment evaluates your understanding of Bloodborne Pathogens (BBP), infection control practices, and OSHA safety requirements.', 0, 0, 10, NULL, NULL, NULL),
(21, 'Start', '0:05:00', 7, 23, NULL, NULL, NULL, NULL, 1768723200, NULL, 'quiz', '{\"total_marks\":\"50\",\"pass_mark\":\"10\",\"drip_content_for_passing_rule\":\"not_applicable\"}', 'json', NULL, 'Test', 0, 0, 5, NULL, NULL, NULL),
(23, 'Reporting Procedures &amp; Support Resources', '0:00:00', 11, 24, NULL, NULL, NULL, NULL, 1768809600, NULL, 'quiz', '{\"total_marks\":\"10\",\"pass_mark\":\"5\",\"drip_content_for_passing_rule\":\"not_applicable\"}', 'json', NULL, 'Answer all questions carefully. This quiz tests your understanding of recognizing and reporting suspected human trafficking in hospitality settings.', 0, 0, 4, NULL, NULL, NULL),
(24, 'Human Trafficking Awareness for the Hospitality Industry', '0:00:00', 12, 25, NULL, NULL, NULL, NULL, 1768809600, NULL, 'quiz', '{\"total_marks\":\"20\",\"pass_mark\":\"10\",\"drip_content_for_passing_rule\":\"not_applicable\"}', 'json', NULL, 'Answer all questions carefully. This quiz tests your understanding of recognizing and reporting suspected human trafficking in hospitality settings.', 0, 0, 5, NULL, NULL, NULL),
(25, 'Emergency Evacuation, Fire Safety &amp; Reporting (OSHA 29 CFR 1910.38)', '0:00:00', 9, 16, NULL, NULL, NULL, NULL, 1769673600, NULL, 'quiz', '{\"total_marks\":\"50\",\"pass_mark\":\"35\",\"drip_content_for_passing_rule\":\"not_applicable\"}', 'json', NULL, '', 0, 0, 4, NULL, NULL, NULL),
(26, ' HIPAA Compliance Training: Privacy &amp; Security Essentials Certification | HRC Service', '0:00:00', 13, 27, NULL, NULL, NULL, NULL, 1771747200, NULL, 'quiz', '{\"total_marks\":\"50\",\"pass_mark\":\"35\",\"drip_content_for_passing_rule\":\"applicable\"}', 'json', NULL, 'Course Instructions\r\nWelcome to the HIPAA Compliance Training: Privacy &amp; Security Essentials Certification course provided by HRC Service.\r\n\r\nThis course is designed to help you understand the key requirements of the HIPAA Privacy Rule and Security Rule, and how they apply to your workplace responsibilities.\r\n\r\nPlease read the following instructions carefully before beginning the course.\r\n\r\nHow to Complete This Course\r\n\r\nReview All Modules\r\nComplete each lesson in order. The course is structured to build your understanding step by step.\r\n\r\nPay Attention to Real-World Scenarios\r\nExamples and workplace situations are included to help you apply HIPAA requirements in practical settings.\r\n\r\nComplete Knowledge Checks\r\nYou may be required to complete short quizzes or assessments to reinforce learning.\r\n\r\nFinal Assessment\r\nAt the end of the course, you must successfully complete the final assessment to receive certification.\r\n\r\nDownload Certificate\r\nAfter passing the final assessment, your certificate of completion will be available for download.', 0, 0, 4, NULL, NULL, NULL),
(27, 'The Complete Guide to FLSA, PTO, and Workforce Security', NULL, 18, 28, NULL, NULL, NULL, NULL, 1781679600, NULL, 'text', '&lt;p&gt;test&lt;/p&gt;', 'description', NULL, '&lt;p&gt;test&lt;/p&gt;', 0, 0, 0, NULL, NULL, NULL);
