INSERT INTO `newsletter_histories` (`id`, `email`, `subject`, `description`, `status`, `tried_times`, `sent_at`, `created_at`, `updated_at`) VALUES
(188, 'MLPAT84@GMAIL.COM', 'Mandatory Training By Your Employer & HR', '<!DOCTYPE html>\n<html>\n<head>\n  <title>Mandatory Training By Your Employer & HR</title>\n</head>\n<body style=\"font-family: Arial, sans-serif; background-color: #f5f5f5; margin: 0; padding: 0;\">\n  <div style=\"max-width: 600px; margin: 0 auto; background-color: #ffffff; padding: 40px; border-radius: 8px; box-shadow: 0 4px 8px rgba(0, 0, 0, 0.1); text-align: center;\">\n\n    <!-- Logo -->\n    <div style=\"text-align: center; margin-bottom: 20px;\">\n      <img src=\"https://lms.hrchr.com/uploads/system/6e03a3928e2f0af1aacfc88f28e4c94f.png\" alt=\"Website Logo\" width=\"250\" height=\"auto\">\n    </div>\n\n    <!-- Email subject -->\n    <h1 style=\"color: #333333; font-size: 25px; text-align: center; margin-bottom: 20px;\">Mandatory Training By Your Employer & HR</h1>\n\n    <!-- Email body -->\n    <!-- Start and end hidden div are needed for tracking system notification. SO don\'t remove -->\n    <div class=\"system_notification_start\" style=\"display: none;\"></div>\n    <div><p><span style=\"color: rgb(34, 34, 34); font-family: Arial, Helvetica, sans-serif; font-size: small;\">Dear Team Member,</span><br style=\"color: rgb(34, 34, 34); font-family: Arial, Helvetica, sans-serif; font-size: small;\"><br style=\"color: rgb(34, 34, 34); font-family: Arial, Helvetica, sans-serif; font-size: small;\"><span style=\"color: rgb(34, 34, 34); font-family: Arial, Helvetica, sans-serif; font-size: small;\">As part of our commitment to maintaining a safe and respectful workplace, we are requiring all employees to complete a mandatory training. This training is designed to help you recognize and prevent potential workplace violence, ensuring a secure environment for everyone.</span><br style=\"color: rgb(34, 34, 34); font-family: Arial, Helvetica, sans-serif; font-size: small;\"></p><p><b>For mobile app, you can go to Google play store or Apple\'s iOs store and download the HRCHR- LMS App</b></p><p><br style=\"color: rgb(34, 34, 34); font-family: Arial, Helvetica, sans-serif; font-size: small;\"><span style=\"color: rgb(34, 34, 34); font-family: Arial, Helvetica, sans-serif; font-size: small;\"><b>Training Details:</b></span><br style=\"color: rgb(34, 34, 34); font-family: Arial, Helvetica, sans-serif; font-size: small;\"><br style=\"color: rgb(34, 34, 34); font-family: Arial, Helvetica, sans-serif; font-size: small;\"><b><span style=\"color: rgb(34, 34, 34); font-family: Arial, Helvetica, sans-serif; font-size: small;\">Workplace Violence Prevention Training Program</span><br style=\"color: rgb(34, 34, 34); font-family: Arial, Helvetica, sans-serif; font-size: small;\"><span style=\"color: rgb(34, 34, 34); font-family: Arial, Helvetica, sans-serif; font-size: small;\">Deadline:  Friday, October 30, 2024</span><br style=\"color: rgb(34, 34, 34); font-family: Arial, Helvetica, sans-serif; font-size: small;\"><span style=\"color: rgb(34, 34, 34); font-family: Arial, Helvetica, sans-serif; font-size: small;\">Estimated Completion Time: 10 minutes</span></b></p><p><b> Laptop or Desktop</b></p><p><b><br></b></p><ol><li><b>Click the link Below<br style=\"color: rgb(34, 34, 34); font-family: Arial, Helvetica, sans-serif; font-size: small;\"><span style=\"color: rgb(34, 34, 34); font-family: Arial, Helvetica, sans-serif; font-size: small;\">Link to Training: <a href=\"http://www.lms.hrchr.com\" target=\"_blank\">www.lms.hrchr.com</a></span></b></li><li><span style=\"color: rgb(34, 34, 34); font-family: Arial, Helvetica, sans-serif; font-size: small;\"><b>Register</b></span></li><li><span style=\"color: rgb(34, 34, 34); font-family: Arial, Helvetica, sans-serif; font-size: small;\"><b>Select Course (English or Spanish)</b></span></li><li><span style=\"color: rgb(34, 34, 34); font-family: Arial, Helvetica, sans-serif; font-size: small;\"><b>Complete Course and Download the Certificate </b><br></span></li><li><span style=\"color: rgb(34, 34, 34); font-family: Arial, Helvetica, sans-serif; font-size: small;\"><br></span><span style=\"color: rgb(34, 34, 34); font-family: Arial, Helvetica, sans-serif; font-size: small;\">Please complete the training by the deadline. If you encounter any issues accessing the link or have any questions, feel free to reach out to Maria Khan, Human Resources at 818-920-6000 X105.</span><br style=\"color: rgb(34, 34, 34); font-family: Arial, Helvetica, sans-serif; font-size: small;\"><br style=\"color: rgb(34, 34, 34); font-family: Arial, Helvetica, sans-serif; font-size: small;\"><span style=\"color: rgb(34, 34, 34); font-family: Arial, Helvetica, sans-serif; font-size: small;\">Thank you for your attention to this important matter and for your continued dedication to creating a safe workplace for everyone.</span><br style=\"color: rgb(34, 34, 34); font-family: Arial, Helvetica, sans-serif; font-size: small;\"><br style=\"color: rgb(34, 34, 34); font-family: Arial, Helvetica, sans-serif; font-size: small;\"></li></ol><div style=\"color: rgb(34, 34, 34); font-family: Arial, Helvetica, sans-serif; font-size: small;\"><div dir=\"ltr\" class=\"gmail_signature\" data-smartmail=\"gmail_signature\"><div dir=\"ltr\"><div style=\"color: rgb(0, 0, 0);\"><span style=\"font-family: \" comic=\"\" sans=\"\" ms\",=\"\" sans-serif;\"=\"\">Sincerely,</span></div><div style=\"color: rgb(0, 0, 0);\"><br></div><div style=\"color: rgb(0, 0, 0);\"><font face=\"comic sans ms, sans-serif\">Maria Khan</font></div><div style=\"color: rgb(0, 0, 0);\"><font face=\"comic sans ms, sans-serif\"><br></font></div><div style=\"color: rgb(0, 0, 0);\"><font size=\"1\" face=\"comic sans ms, sans-serif\">VP of Human Resources<br>Hospitality Resource Center (HRC), LLC<br>27703 Zeus Ln<br>Santa Clarita, CA 91351<br>Phone: 818-920-6000<br>Fax: 661-250-8128</font></div><div style=\"color: rgb(0, 0, 0);\"><font size=\"1\" face=\"comic sans ms, sans-serif\"><a href=\"http://www.hrcservice.com/\" target=\"_blank\" data-saferedirecturl=\"https://www.google.com/url?q=http://www.hrcservice.com/&source=gmail&ust=1727540993400000&usg=AOvVaw2FaPNQYWaUTG3kPHqNhPP6\" style=\"color: rgb(17, 85, 204);\">www.hrcservice.com</a></font></div><div style=\"color: rgb(0, 0, 0);\"><p class=\"MsoNormal\" style=\"margin-right: 0px; margin-bottom: 0px; margin-left: 0px;\"><span style=\"color: rgb(31, 73, 125);\"><font size=\"1\" face=\"comic sans ms, sans-serif\">Please Note:</font></span></p><p class=\"MsoNormal\" style=\"margin-right: 0px; margin-bottom: 0px; margin-left: 0px;\"></p><p class=\"MsoNormal\" style=\"margin-right: 0px; margin-left: 0px;\"><font size=\"1\" face=\"comic sans ms, sans-serif\"><span style=\"color: rgb(31, 73, 125);\">The information in this E-mail message, and any files transmitted with it, is confidential and may be legally privileged. It is intended only for the use of the individual(s) named above. If you are the intended recipient, be aware that your use of any confidential or personal information may be restricted by state and federal privacy laws. If you, the reader of this message, are not the intended recipient, you are hereby notified that you should not further disseminate, distribute, or forward this E-mail message. If you have received this E-mail in error, please notify the sender and delete the material from any computer. Thank</span><span style=\"color: rgb(31, 73, 125);\"> you.</span></font></p></div></div></div></div></div>\n    <div class=\"system_notification_end\" style=\"display: none;\"></div>\n\n    <!-- Email footer -->\n    <p style=\"text-align: center; margin-top: 40px; color: #999999; font-size: 14px;\">&copy; 2024 HRCHR LMS. All rights reserved.</p>\n  </div>\n</body>\n</html>\n', 'sent', 1, '1728690590', '1728690231', '1728690590'),
