(1, 3, '&lt;p&gt;&lt;b&gt;How many types of workplace violence are there ?&lt;/b&gt;&lt;/p&gt;', 'multiple_choice', 4, '[\"2\",\"4\",\"5\",\"8\"]', '[\"2\"]', 0),
(2, 3, '&lt;p&gt;&lt;span zm=&quot;&quot; style=&quot;font-family: &#039;Segoe UI&#039;;&quot;&gt;What are some signs of potential violence ?&lt;/span&gt;&lt;br&gt;&lt;/p&gt;', 'multiple_choice', 4, '[\"Sudden changes in behavior\",\"Verbal threats\",\"Rage\",\"All of the above\"]', '[\"4\"]', 0),
(3, 3, '&lt;p&gt;&lt;span zm=&quot;&quot; style=&quot;font-family: &#039;Segoe UI&#039;;&quot;&gt;Verbal harassment does not count as workplace violence ?&lt;/span&gt;&lt;br&gt;&lt;/p&gt;', 'single_choice', 2, '[\"True\",\"False\"]', '[\"1\"]', 0),
(4, 3, '&lt;p&gt;&lt;span zm=&quot;&quot; style=&quot;font-family: &#039;Segoe UI&#039;;&quot;&gt;Everyone in the workplace may be affected by a violent incident. Is this statement true or false ?&lt;/span&gt;&lt;br&gt;&lt;/p&gt;', 'single_choice', 2, '[\"True\",\"False\"]', '[\"1\"]', 0),
