(1, 'Reza', 'Khan', 'reza@hrcservice.com', NULL, NULL, '04ce65d5ef8ac482546f11fc79bb7759f4a819f3', '', '', 0, '', '{\"facebook\":\"\",\"twitter\":\"\",\"linkedin\":\"https:\\/\\/www.linkedin.com\\/in\\/reza-khan-3075759\\/\"}', '', 1, NULL, 1742150764, NULL, 'HRC Service LLC was established in the year 2005 under the visionary leadership of Reza Khan, a seasoned expert with an impressive career spanning 34 years in the hospitality sector. Initially conceived as a support system for the hospitality industry, HRC Service was born out of a desire to provide exceptional, targeted solutions within this bustling industry.\r\n\r\nOver the years, our humble beginnings gave way to expansive growth. Today, we have broadened our horizons to extend our comprehensive suite of services across diverse sectors, thereby increasing our reach and impact.\r\n\r\nWe have evolved into a distinguished provider of top-tier payroll processing, a go-to for outsourced human resources, and a trusted partner for time and attendance software. Additionally, we excel in labor management services, implementing best practices that facilitate operational efficiency and contribute to our clients’ success.\r\n\r\nRooted in rich industry experience and committed to delivering bespoke solutions tailored to our clients’ needs, HRC Service continues to redefine service standards, establishing itself as an undeniable industry leader', '', '290979', 1, 1, '838b197e993d6fd502c0b5d7755ec2fc', NULL, ''),
(2, 'Abdun Nur', 'Tomal', 'tomal.nur@gmail.com', '01965824332', 'Bangladesh', 'eaeb5c33ec7607d4b4ea1528c319ef4ba8ab5e55', '', '', 0, '', '{\"facebook\":\"\",\"twitter\":\"\",\"linkedin\":\"\"}', 'Test', 1, 1726422323, 1761058678, '[]', NULL, '', 'dG9tYWwubnVyX19nbWFpbC5jb20tLTI5Njk', 1, 1, 'dc49adc9a9d7b9a61ee835f130fda13a', NULL, ''),
